--
-- Table structure for table `order_message`
--

DROP TABLE IF EXISTS `order_message`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `order_message` (
  `id` bigint NOT NULL AUTO_INCREMENT COMMENT '消息ID',
  `order_id` bigint DEFAULT '0' COMMENT '关联订单ID(0为通用咨询)',
  `sender_type` tinyint(1) NOT NULL COMMENT '发送者类型(1:客户 2:管理员)',
  `content` text NOT NULL COMMENT '消息内容',
  `image_url` varchar(255) DEFAULT NULL COMMENT '图片路径(可选)',
  `create_time` datetime DEFAULT CURRENT_TIMESTAMP COMMENT '发送时间',
  `customer_id` bigint DEFAULT '0' COMMENT '所属客户ID',
  `is_ai` char(1) DEFAULT '0' COMMENT '是否为AI消息(0否 1是)',
  PRIMARY KEY (`id`),
  KEY `idx_order_id` (`order_id`) USING BTREE
) ENGINE=InnoDB AUTO_INCREMENT=111 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci COMMENT='订单留言记录表';
/*!40101 SET character_set_client = @saved_cs_client */;

