INSERT INTO `visa_knowledge` VALUES (3,'美国','美国B1/B2签证材料要求','美国签证,B1,B2,材料,申请','申请美国B1/B2旅游/商务签证需要准备以下材料：\n1. 有效护照（有效期须超过赴美预定停留日期后6个月）\n2. DS-160在线申请表（已提交并打印确认页）\n3. 签证照片（白底，2英寸×2英寸）\n4. 银行存款证明（近3个月流水及存款余额，建议10万元以上）\n5. 在职证明/营业执照（证明有稳定工作或生意）\n6. 房产证/车产证（资产证明）\n7. 行程单（机票预订单、酒店预订单）\n8. 往来记录（如有赴美历史记录，效果更佳）','0','2026-04-19 11:28:56','[-0.06187565624713898,-0.003248684573918581,0.019864296540617943,-0.008748230524361134,0.01248430646955967,0.04684627801179886,0.01773749850690365,-0.007185033988207579,0.010485116392374039,0.0716305673122406,0.029236389324069023,-0.02525218576192856,-0.06783068925142288,0.06658297032117844,0.05294310301542282,-0.023933570832014084,0.001657130429521203,-0.03799879923462868,-0.051525235176086426,0.010173185728490353,0.030313966795802116,0.04023902490735054,0.018971040844917297,0.014944303780794144,0.049908868968486786,0.014334620907902718,0.07917361706495285,0.0046505993232131004,-0.022487347945570946,0.025464866310358047,-0.02601783350110054,-0.02946324646472931,-0.05087301880121231,-0.01959490217268467,-0.014887589029967785,5.037853843532503E-4,-0.010343329049646854,0.03992709517478943,0.03434070572257042,-0.02019040659070015,0.023196281865239143,2.001627435674891E-4,-0.031930334866046906,0.03317805379629135,0.04486126825213432,0.09068668633699417,-0.043131470680236816,0.002094896510243416,-0.015639057382941246,0.018446430563926697,0.016943493857979774,-0.043131470680236816,0.010853760875761509,0.030002035200595856,0.039416663348674774,-0.0361555740237236,-0.013278311118483543,0.02506786398589611,0.0065328157506883144,0.032951194792985916,0.010506384074687958,0.023905213922262192,0.051071517169475555,0.005526131018996239,0.026882732287049294,-0.02606036886572838,0.009733647108078003,0.021367235109210014,0.02145230583846569,-0.020162047818303108,0.025365615263581276,-0.025720082223415375,-0.009655664674937725,-0.01622038148343563,-0.02123962715268135,0.030115464702248573,-0.03607049956917763,0.05852949246764183,-0.017865106463432312,0.0014