--
-- Table structure for table `visa_order`
--

DROP TABLE IF EXISTS `visa_order`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `visa_order` (
  `id` bigint NOT NULL AUTO_INCREMENT COMMENT '订单ID',
  `order_no` varchar(32) NOT NULL COMMENT '订单编号(唯一)',
  `customer_id` bigint NOT NULL COMMENT '客户ID(关联c_customer)',
  `product_id` bigint NOT NULL COMMENT '产品ID(关联visa_product)',
  `quantity` int DEFAULT '1' COMMENT '订单数量',
  `product_snapshot` json DEFAULT NULL COMMENT '产品信息快照(存下单时的标题和价格)',
  `total_amount` decimal(10,2) NOT NULL COMMENT '订单总金额',
  `status` bigint DEFAULT '0' COMMENT '订单状态(0待支付 1待上传 2待审核 3待补交 4办理中 5待收货 6已完成 7待面试)',
  `alipay_no` varchar(64) DEFAULT NULL COMMENT '支付宝交易流水号',
  `pay_time` datetime DEFAULT NULL COMMENT '支付成功时间',
  `submitted_materials` json DEFAULT NULL COMMENT '用户提交的动态材料数据(JSON)',
  `audit_remark` varchar(500) DEFAULT NULL COMMENT '审核备注/驳回原因',
  `interview_time` datetime DEFAULT NULL COMMENT '预约面试时间',
  `interview_file` varchar(255) DEFAULT NULL COMMENT '面试预约单文件路径',
  `interview_feedback` json DEFAULT NULL COMMENT '面试结果',
  `visa_result` json DEFAULT NULL COMMENT '最终签证结果',
  `mailing_address` json DEFAULT NULL COMMENT '收货地址快照(收件人,电话,地址)',
  `create_time` datetime DEFAULT NULL COMMENT '下单时间',
  `update_time` datetime DEFAULT NULL COMMENT '更新时间',
  `del_flag` char(1) DEFAULT '0' COMMENT '删除标志(0代表存在 2代表删除)',
  `interview_slots` json DEFAULT NULL COMMENT '管理员提供的备选时间点',
  `supplementary_materials` json DEFAULT NULL COMMENT '面试后补交的特殊材料',
  `is_commented` char(1) DEFAULT '0' COMMENT '是否评价(0未评 1已评)',
  `user_remark` varchar(500) DEFAULT NULL COMMENT '用户备注/面试时间反馈要求',
  PRIMARY KEY (`id`),
  UNIQUE KEY `uk_order_no` (`order_no`) USING BTREE,
  KEY `idx_customer_id` (`customer_id`) USING BTREE,
  KEY `idx_status` (`status`) USING BTREE
) ENGINE=InnoDB AUTO_INCREMENT=78 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci COMMENT='签证订单表';
/*!40101 SET character_set_client = @saved_cs_client */;

--
-- Dumping data for table `visa_order`
--

