CREATE TABLE `visa_order_applicant` (
  `id` bigint NOT NULL AUTO_INCREMENT COMMENT '主键ID',
  `order_id` bigint NOT NULL COMMENT '关联订单ID',
  `order_no` varchar(32) NOT NULL COMMENT '关联订单号',
  `name` varchar(50) NOT NULL COMMENT '姓名',
  `id_card` varchar(20) DEFAULT NULL COMMENT '身份证号',
  `passport_no` varchar(20) DEFAULT NULL COMMENT '护照号',
  `identity` varchar(20) DEFAULT 'ADULT' COMMENT '身份类型: ADULT(在职), CHILD(未成年), STUDENT(学生), RETIRED(退休)',
  `create_time` datetime DEFAULT NULL COMMENT '创建时间',
  PRIMARY KEY (`id`)
) ENGINE=InnoDB AUTO_INCREMENT=29 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci COMMENT='订单申请人基本信息表';
